export function parseSjis2004Additions(): Map<number, number[]> {
  const map = new Map<number, number[]>();
  for (let i = 0; i < SJIS2004_RAW.length; i += 2) {
    const cp = SJIS2004_RAW[i];
    const w = SJIS2004_RAW[i + 1];
    map.set(cp, [w >> 8, w & 0xFF]);
  }
  return map;
}
